// Собираем все отчёты из всех недель
const items = $input.all();
const allReports = [];

function esc(s) {
  if (s === null || s === undefined) return '';
  return String(s).replace(/'/g, "''");
}

function parseNum(val) {
  if (val === null || val === undefined || val === '') return 0;
  if (typeof val === 'number') return val;
  const cleaned = String(val).replace(/\s/g, '').replace(',', '.');
  return parseFloat(cleaned) || 0;
}

for (const item of items) {
  let reports = item.json;
  if (!Array.isArray(reports)) {
    if (reports && typeof reports === 'object') reports = [reports];
    else continue;
  }

  for (const r of reports) {
    if (!r.id) continue;
    allReports.push({
      json: {
        id: esc(r.id),
        number: esc(r.number || ''),
        date_from: r.date_from || null,
        date_to: r.date_to || null,
        driver_id: esc(r.driver_id || ''),
        driver_name: esc(r.driver_name || ''),
        vehicle_id: esc(r.vehicle_id || ''),
        vehicle_number: esc(r.vehicle_number || ''),
        fuel_start: parseNum(r.fuel_start),
        fuel_end: parseNum(r.fuel_end),
        mileage: Math.round(parseNum(r.mileage)),
        fuel_quantity: parseNum(r.fuel_quantity),
        fuel_amount: parseNum(r.fuel_amount),
        total_expenses: parseNum(r.total_expenses),
        driver_accruals: parseNum(r.driver_accruals),
        driver_payments: parseNum(r.driver_payments),
        expense_categories: JSON.stringify(r.expense_categories || [])
      }
    });
  }
}

console.log('Driver Reports:', allReports.length);
return allReports;

